import * as React from 'react';
import { useMemo } from 'react';

import * as ToggleGroupPrimitive from '@radix-ui/react-toggle-group';
import type { VariantProps } from 'class-variance-authority';
import { cva } from 'class-variance-authority';

import { cn } from '../utils/cn';
import { spacingLength } from '../utils/tw3-compat';
import { toggleVariants } from './common/variants';

const ToggleGroupContext = React.createContext<
  VariantProps<typeof toggleVariants> & {}
>({
  size: 'md',
});

const toggleGroupVariants = cva(
  [
    'group/toggle-group flex items-stretch gap-[var(--gap)] rounded-md',
    'bg-transparent',
    'data-[orientation=vertical]:flex-col',
  ],
  {
    variants: {
      variant: {
        outline: 'border border-input p-1',
        default: null,
      },
    },
    defaultVariants: {
      variant: 'default',
    },
  }
);

export type ToggleGroupProps = React.ComponentProps<
  typeof ToggleGroupPrimitive.Root
> &
  VariantProps<typeof toggleGroupVariants> & {
    spacing?: number;
    size?: VariantProps<typeof toggleVariants>['size'];
  };

/**
 * A set of two-state buttons that can be toggled on or off.
 */
function ToggleGroup({
  className,
  children,
  spacing = 0,
  orientation = 'horizontal',
  variant = 'default',
  /* variants to set for child items */
  size,
  ...props
}: ToggleGroupProps) {
  const contextValue = useMemo(
    () => ({
      size,
    }),
    [size]
  );
  return (
    <ToggleGroupPrimitive.Root
      data-slot="toggle-group"
      style={{ '--gap': spacingLength(spacing) } as React.CSSProperties}
      data-size={size}
      data-spacing={spacing}
      data-orientation={orientation}
      className={cn(toggleGroupVariants({ variant }), className)}
      {...props}
    >
      <ToggleGroupContext.Provider value={contextValue}>
        {children}
      </ToggleGroupContext.Provider>
    </ToggleGroupPrimitive.Root>
  );
}

/**
 * An item within a ToggleGroup.
 *
 * Will apply Toggle `size` variant styling.
 *
 * Note that this does not directly use the Toggle component from this library.
 * For more control over items in ToggleGroups, use `asChild` and compose with
 * a Toggle component.
 *
 * @example
 * <ToggleGroup variant="outline">
 *   <ToggleGroupItem asChild>
 *     <Toggle><SomeIcon />Whatever you want in here</Toggle>
 *   </ToggleGroupItem>
 * </ToggleGroup>
 */
function ToggleGroupItem({
  className,
  children,
  size,
  ...props
}: React.ComponentProps<typeof ToggleGroupPrimitive.Item> &
  VariantProps<typeof toggleVariants>) {
  const context = React.useContext(ToggleGroupContext);

  return (
    <ToggleGroupPrimitive.Item
      data-slot="toggle-group-item"
      data-size={context.size || size}
      className={cn(
        toggleVariants({
          size: context.size || size,
        }),
        'shrink-0 focus:z-10 focus-visible:z-10',
        className
      )}
      {...props}
    >
      {children}
    </ToggleGroupPrimitive.Item>
  );
}

export { ToggleGroup, ToggleGroupItem };
